import{c as a,Q as t,j as o,m as d}from"./chunks/framework.D9IbVcwA.js";const g=JSON.parse('{"title":"017-mm-heap-2 · 堆管理","description":"","frontmatter":{"title":"017-mm-heap-2 · 堆管理"},"headers":[],"relativePath":"hands-on/017-mm-heap-2.md","filePath":"hands-on/017-mm-heap-2.md","lastUpdated":1779686691000}'),l={name:"hands-on/017-mm-heap-2.md"};function r(p,e,i,n,s,c){return t(),o("div",null,[...e[0]||(e[0]=[d(`<h1 id="_017-2-first-fit-分配与块分裂" tabindex="-1">017-2 First-fit 分配与块分裂 <a class="header-anchor" href="#_017-2-first-fit-分配与块分裂" aria-label="Permalink to &quot;017-2 First-fit 分配与块分裂&quot;">​</a></h1><h2 id="导语" tabindex="-1">导语 <a class="header-anchor" href="#导语" aria-label="Permalink to &quot;导语&quot;">​</a></h2><p>上一章我们把堆的骨架搭好了——BlockHeader 定义完毕，init 能映射物理页并创建初始空闲块，dump_stats 能报告堆的健康状况。但这个堆现在还只是个空壳子：它只能坐在那里占据 64 KB 的虚拟地址空间，一个字节都分配不出去。本章我们要给它装上&quot;收银台&quot;——实现 <code>Heap::alloc()</code> 函数，让内核真正能按需获取任意大小的内存块。</p><p>alloc 的核心逻辑是 first-fit 搜索：从空闲链表头部开始，找到第一个足够大的空闲块，从中切出请求的大小，剩余部分如果足够大就分裂成一个新的空闲块。听起来很简单对吧？但实际实现中有好几个微妙的地方——对齐处理、front padding、最小分裂阈值——每一处都可能藏着一个让你调试到半夜的 bug。</p><p>知识前置：你需要理解上一章的 BlockHeader 布局（32 字节头部 + payload）和空闲链表的结构。本章的代码会频繁操作链表节点的插入和删除，所以基本的链表操作要烂熟于心。</p><p>本章的核心代码在 <code>kernel/mm/heap.cpp</code> 的前半部分（约 1-180 行），包括三个内部辅助函数和 <code>alloc()</code> 函数。<code>alloc()</code> 是整个堆分配器最复杂也最有趣的部分——它要处理 first-fit 搜索、对齐计算、front padding、块分裂。</p><h2 id="概念精讲" tabindex="-1">概念精讲 <a class="header-anchor" href="#概念精讲" aria-label="Permalink to &quot;概念精讲&quot;">​</a></h2><h3 id="first-fit-策略-第一个够大的就是它" tabindex="-1">First-fit 策略：第一个够大的就是它 <a class="header-anchor" href="#first-fit-策略-第一个够大的就是它" aria-label="Permalink to &quot;First-fit 策略：第一个够大的就是它&quot;">​</a></h3><p>堆分配器有多种搜索策略，最常见的三种是 first-fit（首次适应）、best-fit（最佳适应）和 worst-fit（最差适应）。first-fit 从链表头部开始线性扫描，遇到的第一个大小足够的空闲块就拿来用；best-fit 遍历整个链表，找最小的那个足够大的块；worst-fit 找最大的块来分配（试图保留小空闲块的完整）。理论上 best-fit 产生的碎片最少，但每次分配都要遍历整个链表，O(n) 的开销在实践中不可忽视。first-fit 只需要找到第一个够大的就停下来，平均搜索长度是 best-fit 的一半左右。</p><p>Cinux 选择 first-fit 的原因很简单——它足够简单，足够快，碎片化程度在内核工作负载下完全可以接受。Linux 内核的 SLOB 分配器也使用 first-fit（在三个按大小分段的链表上），说明这个策略在量产环境中也是可行的。FreeRTOS 的 heap_4 同样使用 first-fit，这基本上是教学和小型 RTOS 的标准选择。</p><p>值得注意的是，first-fit 的性能取决于空闲链表的大小和请求的分布。如果空闲链表很长（几百个碎片块），每次分配都要扫描大量小块才能找到够用的。SLOB 通过按大小分级来缓解这个问题——小请求只在小块链表中搜索。Cinux 的内核堆在可预见的未来不会有这么多的空闲块，所以单链表 first-fit 足够用。</p><h3 id="块分裂-别浪费多余的空间" tabindex="-1">块分裂：别浪费多余的空间 <a class="header-anchor" href="#块分裂-别浪费多余的空间" aria-label="Permalink to &quot;块分裂：别浪费多余的空间&quot;">​</a></h3><p>当我们找到一个空闲块时，它的大小可能远远大于请求的大小。比如请求 64 字节，但找到的空闲块有 60000 字节的 payload 空间。如果把整个 60000 字节都分配出去，浪费就太大了。所以我们需要&quot;分裂&quot;——把原块切成两部分：前面一部分（用户请求的大小 + 头部）变成已分配块，后面剩余的部分变成一个新的空闲块。</p><p>分裂发生在空闲块的尾部（tail splitting），而不是头部。这是因为分配块的 header 必须紧贴在 payload 前面（否则 header_from_ptr 无法工作），所以 payload 的位置由对齐计算决定，header 放在 payload 前面，剩余的空间在 payload 之后。Tail splitting 在 <code>aligned_payload + size</code> 的位置创建新的空闲块。</p><p>但不是所有的剩余空间都值得分裂。如果分裂后剩余部分太小（不够放一个 BlockHeader 加上最小的 payload），那么创建一个几乎无用的碎片块反而会加剧碎片化。Cinux 设定了一个最小分裂阈值 MIN_SPLIT = HEADER_SIZE + 16 = 48 字节——如果尾部剩余空间不足 48 字节，就不分裂，这部分空间就成了&quot;内部碎片&quot;（internal fragmentation），跟着分配块一起被占用，直到这个块被释放。</p><p>48 字节这个数字是怎么来的？HEADER_SIZE 是 32 字节，这是创建一个新块头的硬性开销。再加上 16 字节的最小 payload——如果 payload 小于 16 字节，这个空闲块几乎不可能被任何有意义的分配请求命中，它就变成了&quot;死碎片&quot;。所以 32 + 16 = 48 是确保分裂后的新空闲块&quot;有存在价值&quot;的最低门槛。</p><p>如果你把 MIN_SPLIT 设得太小（比如 32，即只够放一个 header 没有 payload），空闲链表中会出现很多永远无法满足任何分配的&quot;僵尸块&quot;——它们白白占据了链表遍历的时间，却永远不可能被选中。如果设得太大（比如 128），则过于保守，大量的 tail remainder 被浪费为内部碎片。48 是一个在两者之间的平衡点。</p><h3 id="对齐-让指针站在整齐的地址上" tabindex="-1">对齐：让指针站在整齐的地址上 <a class="header-anchor" href="#对齐-让指针站在整齐的地址上" aria-label="Permalink to &quot;对齐：让指针站在整齐的地址上&quot;">​</a></h3><p>很多数据结构对内存地址的对齐有要求——比如 SSE 指令要求数据 16 字节对齐，某些硬件 DMA 描述符要求 4096 字节页对齐。Cinux 的 alloc 接受一个 align 参数（默认 16），保证返回的 payload 地址是 align 的整数倍。</p><p>对齐处理的关键在于&quot;front padding&quot;（前填充）。假设你找到一个空闲块，它的 payload 区域从地址 0x100020 开始，但你需要 4096 字节对齐。最近的 4096 对齐地址是 0x101000，两者之间有大约 4KB 的间隙。分配器会把 BlockHeader 放在 <code>0x101000 - 32 = 0x100FE0</code> 的位置（紧贴在 payload 前面），而 0x100020 到 0x100FE0 之间这段空间就是 front padding。如果这段空间足够大（&gt;= MIN_SPLIT），就可以创建一个小空闲块；否则就作为内部碎片浪费掉。</p><p>对齐对性能的影响不仅体现在硬件要求上——对齐的数据访问通常更快。x86-64 的 L1 缓存行是 64 字节，如果一个 16 字节的数据结构跨越了两个缓存行，读取它需要两次缓存访问。如果数据结构对齐到 16 字节，它最多只占据两个缓存行的一半（16 / 64 = 0.25 行），访问效率更高。这就是为什么 alloc 默认 16 字节对齐——不是为了满足硬件的最低要求，而是为了更好的缓存性能。</p><p>这里有一个非常关键的设计决策：分配块的 BlockHeader 不一定在空闲块的起始位置！当存在 front padding 时，头部位于 <code>aligned_payload - HEADER_SIZE</code>，而不是原来空闲块的开头。这意味着在 free 的时候，从 payload 指针回退 HEADER_SIZE 就能找到正确的头部——而不需要知道原始空闲块从哪里开始。这就是为什么我们有一个专门的 <code>header_from_ptr</code> 辅助函数：它永远用 <code>ptr - HEADER_SIZE</code> 来定位头部，不依赖任何其他信息。</p><p>front padding 的处理方式有两种选择：一是把它浪费掉（内部碎片），二是如果够大就复用成一个小的空闲块。Cinux 选择了后者——当 <code>front_pad &gt;= MIN_SPLIT</code> 时，把原始空闲块的 header 缩短，剩余部分变成一个小空闲块。这样即使大对齐请求产生了 front padding，空间也不会被完全浪费。</p><h3 id="alloc-0-的语义" tabindex="-1">alloc(0) 的语义 <a class="header-anchor" href="#alloc-0-的语义" aria-label="Permalink to &quot;alloc(0) 的语义&quot;">​</a></h3><p>按照 C 标准库的惯例，<code>malloc(0)</code> 的行为是 implementation-defined 的——可以返回 nullptr，也可以返回一个唯一的非空指针。Cinux 选择返回 nullptr，这是最安全的做法——分配零字节在逻辑上没有意义，如果调用者这么做了，很可能是程序有 bug，直接拒绝比返回一个神秘的非空指针要好。</p><p>alloc(0) 返回 nullptr 还有另一个好处：它使得&quot;alloc 失败返回 nullptr&quot;的语义保持一致。调用者不需要区分&quot;因为 size=0 返回了 nullptr&quot;和&quot;因为内存不足返回了 nullptr&quot;——两种情况都是&quot;分配没有成功&quot;。</p><h3 id="alloc-返回清零的内存" tabindex="-1">alloc 返回清零的内存 <a class="header-anchor" href="#alloc-返回清零的内存" aria-label="Permalink to &quot;alloc 返回清零的内存&quot;">​</a></h3><p>alloc 在返回 payload 之前会调用 memzero 把整个 payload 区域清零。这不是 C 标准对 malloc 的要求（malloc 返回的内存内容是未定义的），但对内核堆来说是一个合理的默认行为。它消除了信息泄露的风险（上一个使用者的数据不会泄漏给新的分配者），也省去了调用者每次都要手动 memset 的麻烦。Linux 内核的 <code>kzalloc</code> 提供同样的&quot;清零分配&quot;语义。</p><h2 id="动手实现" tabindex="-1">动手实现 <a class="header-anchor" href="#动手实现" aria-label="Permalink to &quot;动手实现&quot;">​</a></h2><h3 id="step-1-实现内部辅助函数" tabindex="-1">Step 1: 实现内部辅助函数 <a class="header-anchor" href="#step-1-实现内部辅助函数" aria-label="Permalink to &quot;Step 1: 实现内部辅助函数&quot;">​</a></h3><p><strong>目标</strong>: 提供 align_up、header_from_ptr 和 memzero 三个辅助函数。</p><p><strong>设计思路</strong>: <code>align_up(value, align)</code> 是一个经典的位运算技巧：<code>(value + align - 1) &amp; ~(align - 1)</code>。前提是 align 必须是 2 的幂——这个函数只用于内部，调用者保证传入合法的对齐值。<code>header_from_ptr(ptr)</code> 从 payload 指针回退 HEADER_SIZE 字节，得到 BlockHeader 的地址——这是一个简单的指针减法，但必须用 <code>reinterpret_cast</code> 在 uintptr_t 和指针之间转换。<code>memzero(start, len)</code> 逐字节清零——内核里没有 memset 可用（没有标准库），所以需要自己写。</p><p><strong>实现约束</strong>: 三个函数都放在 <code>heap.cpp</code> 的匿名命名空间中（内部链接，不暴露给其他编译单元）。align_up 的参数和返回类型是 uint64_t，header_from_ptr 返回 <code>BlockHeader*</code>。</p><p>这三个函数虽然简单，但每一个都在后续的 alloc、free、coalesce、expand 中被频繁调用。<code>align_up</code> 在 alloc 中用于计算对齐 payload 地址，在 init 和 expand 中用于对齐页面大小。<code>header_from_ptr</code> 是 free 的第一步操作，每次释放都会调用。<code>memzero</code> 在 init、expand 和 alloc 中被调用，确保返回的内存是干净的。</p><p><strong>踩坑预警</strong>: <code>~(align - 1)</code> 中的运算符优先级——<code>~</code> 的优先级高于 <code>-</code>，所以 <code>~align - 1</code> 会被解析为 <code>(~align) - 1</code>，结果完全错误。必须写成 <code>~(align - 1)</code>。这个坑在位操作中非常常见，而且编译器不会给你任何警告。</p><p><strong>验证</strong>: 这些辅助函数的正确性会在后续的 alloc 测试中间接验证——如果 align_up 算错了对齐地址，alloc 返回的指针就不会对齐，测试会立刻失败。</p><h3 id="step-2-实现-alloc-的基本框架" tabindex="-1">Step 2: 实现 alloc 的基本框架 <a class="header-anchor" href="#step-2-实现-alloc-的基本框架" aria-label="Permalink to &quot;Step 2: 实现 alloc 的基本框架&quot;">​</a></h3><p><strong>目标</strong>: 搭建 alloc 函数的骨架——处理零大小请求、对齐下限、搜索循环。</p><p><strong>设计思路</strong>: alloc 的入口做三件事。第一，检查 size 是否为 0——如果是，直接返回 nullptr。第二，把 align 调整到至少 16——低于 16 的对齐要求没有意义（BlockHeader 本身就 32 字节，默认对齐不会低于 16）。第三，计算&quot;需要多大的空闲块才能满足这次分配&quot;：needed = size + (align - 1)。这个公式考虑了最坏情况下的对齐开销——payload 可能需要在空闲块内偏移最多 (align - 1) 字节才能对齐。</p><p>对齐的最低要求为什么是 16 而不是 8？x86-64 的 System V ABI 要求栈上的数据至少 16 字节对齐，SSE 指令（如 <code>movaps</code>）要求操作数 16 字节对齐，否则触发 <code>#GP</code>。既然 alloc 返回的内存可能被用于任何数据结构，16 字节对齐是一个安全的最低要求。</p><p>然后进入 first-fit 搜索循环。用 prev 和 curr 两个指针遍历空闲链表。对每个 curr 块，首先检查 magic 是否正确——如果不正确，说明堆内存被损坏了，立即报错返回 nullptr。然后检查 curr 是否空闲且大小足够。如果条件满足，就进入实际的分配流程（下一步实现）；否则 prev = curr, curr = curr-&gt;next 继续搜索。</p><p><strong>踩坑预警</strong>: needed 的计算可能看起来过于保守——如果空闲块恰好从对齐边界开始，对齐偏移就是 0，不需要任何额外空间。但我们在搜索时不知道空闲块的起始地址是否对齐，所以按最坏情况预估。实际分配时会在循环体内精确计算可用空间，如果不够就跳过（continue）。</p><p>另一个容易出错的地方是搜索循环中的 magic 校验位置。如果你把 magic 校验放在 <code>curr-&gt;free &amp;&amp; curr-&gt;size &gt;= needed</code> 检查之后，那么已分配的块（free=0）会被跳过而不检查 magic。但空闲链表中不应该包含已分配的块——如果有，说明之前的 alloc 或 free 有 bug 把一个已分配的块错误地留在了链表中。所以先检查 magic 是一个防御措施。</p><p><strong>验证</strong>: 单独测试 alloc(0) 应该返回 nullptr。alloc(1) 应该返回一个非空的、16 字节对齐的指针。</p><p>alloc 搜索循环的一个微妙之处是&quot;needed 的计算可能过于保守&quot;。如果空闲块的 payload 恰好从对齐边界开始，对齐偏移就是 0，不需要任何额外空间。但我们在搜索时不知道空闲块的起始地址是否对齐，所以按最坏情况预估。实际分配时会在循环体内精确计算可用空间，不够就跳过——这就是 <code>usable &lt; size</code> 检查的作用。</p><h3 id="step-3-实现分配核心逻辑-对齐-分裂-写头部" tabindex="-1">Step 3: 实现分配核心逻辑（对齐 + 分裂 + 写头部） <a class="header-anchor" href="#step-3-实现分配核心逻辑-对齐-分裂-写头部" aria-label="Permalink to &quot;Step 3: 实现分配核心逻辑（对齐 + 分裂 + 写头部）&quot;">​</a></h3><p><strong>目标</strong>: 在找到合适的空闲块后，计算对齐后的 payload 地址，处理 front padding 和 tail splitting，写入分配块头部。</p><p><strong>设计思路</strong>: 当 first-fit 搜索命中一个足够大的空闲块时，分配过程分六步走。第一步，计算对齐后的 payload 地址：<code>aligned_payload = align_up(curr_addr + HEADER_SIZE, align)</code>。这里 curr_addr 是空闲块的起始虚拟地址，加上 HEADER_SIZE 跳过头部，然后向上对齐到 align。第二步，计算分配块头部应该放在哪里：<code>hdr_addr = aligned_payload - HEADER_SIZE</code>。注意 hdr_addr 不一定等于 curr_addr——如果需要 front padding，hdr_addr 会比 curr_addr 更高。第三步，计算 payload 区域尾部到块末尾还剩多少空间：<code>tail_space = block_end - (aligned_payload + size)</code>。第四步，把当前空闲块从空闲链表中摘除（prev-&gt;next = curr-&gt;next 或 free_list_ = curr-&gt;next）。第五步，处理 front padding——如果 hdr_addr 和 curr_addr 之间的间隙 &gt;= MIN_SPLIT，把原空闲块缩短成一个小的空闲块重新插入链表；否则忽略这段间隙（浪费掉）。第六步，处理 tail splitting——如果 tail_space &gt;= MIN_SPLIT，在分配块之后创建一个新的空闲块并插入链表。最后，在 hdr_addr 位置写入新的 BlockHeader（magic、size、free=0、next=nullptr），更新 used_ 计数器，清零 payload 区域，返回 payload 指针。</p><p>这六步中，从链表摘除当前块（第四步）必须在处理 front padding 和 tail space（第五六步）之前。原因是：front padding 可能复用当前块的 header（curr 保留在链表中成为一个小空闲块），tail space 会创建新的空闲块并插入链表头部。如果先处理 front padding 再摘除，链表操作会变得混乱——curr 可能已经不再是链表中的节点，但 prev 仍然指向它。先摘除再重新挂载，逻辑更清晰。</p><p>这里有一个容易忽略的检查：即使 curr-&gt;size &gt;= needed（空闲块按最坏估计够大），对齐后的实际可用空间 <code>usable = block_end - aligned_payload</code> 可能小于 size。这种情况发生在空闲块虽然&quot;按最坏估计够大&quot;，但实际对齐后 payload 可用空间不够——此时必须跳过这个块，继续搜索下一个。</p><p>这个检查在实际中很少被触发，但在某些边界情况下会出现。例如：空闲块有 100 字节 payload，用户请求 80 字节但需要 4096 对齐。如果空闲块的 payload 区域恰好在 4096 边界之前 100 字节处，对齐后 aligned_payload 被推到下一个 4096 边界，但 block_end 在 aligned_payload 之前——usable 为负数（作为无符号整数会下溢为巨大值），但 <code>usable &lt; size</code> 检查会正确捕获这种情况。</p><p><strong>实现约束</strong>: 所有指针运算通过 <code>reinterpret_cast&lt;uintptr_t&gt;</code> 和 <code>reinterpret_cast&lt;BlockHeader*&gt;</code> 在整数和指针之间转换。尾部新空闲块的 BlockHeader 位于 <code>aligned_payload + size</code> 处，需要设置 magic、size（tail_space - HEADER_SIZE）、free=1，然后插入空闲链表头部。</p><p><strong>踩坑预警</strong>: 这里的最大陷阱是 front padding 场景下的 header_from_ptr。假设空闲块从地址 A 开始，但分配的 payload 在对齐后的地址 P，头部放在 P - 32。当你后来调用 free(P) 时，header_from_ptr 会计算 P - 32，找到正确的头部——但如果你的实现不小心把头部放在了 A（空闲块的起始位置）而不是 P - 32，free 的时候就找不到正确的头部，magic 校验会失败。所以，务必把分配块的头部写在 <code>aligned_payload - HEADER_SIZE</code>，而不是空闲块的起始位置。</p><p>这个陷阱在默认 16 字节对齐下不会触发——因为 BlockHeader 恰好 32 字节（32 是 16 的倍数），空闲块的 payload 起始地址和 allocated payload 地址相同，不需要 front padding。只有当你测试更大的对齐值（如 4096 字节）时，这个 bug 才会浮出水面。所以&quot;alloc(64, 4096) 然后 free&quot;是一个必须包含在测试中的用例。</p><p>另一个坑：front padding 空闲块的 next 指向原来的 free_list_（插入到链表头部），而不是 null。如果你忘了设置 next，这个空闲块就变成了链表的&quot;终点&quot;，后面所有空闲块都无法被搜索到。</p><p>tail splitting 创建的新空闲块也有类似的坑——新块的 next 必须指向当前的 free_list_（不是 nullptr）。如果你把 <code>rem-&gt;next</code> 设为了 nullptr，这个新块就变成了链表的末尾，之前的所有空闲块都被&quot;遗忘&quot;了。这种 bug 在分配少量块时不会出现（因为链表很短），但在压力测试中会导致&quot;堆空间明明够用但分配失败&quot;的现象。</p><p><strong>验证</strong>: 实现完成后，可以写一个简单的测试——连续分配三个 64 字节的块，验证它们返回的指针互不相同且都是 16 字节对齐的。然后调用 dump_stats，检查 used 和 free_total 的数值是否符合预期。</p><p>你也可以用 dump_stats 来验证块分裂是否正确工作。分配一个 64 字节的块后，空闲链表中应该只剩一个块（初始大块的 tail remainder），它的 size 应该约等于 63 KB - 64 = 约 64480 字节（再减去一些 header 开销）。如果 tail splitting 没有执行（free_list 为空），说明 MIN_SPLIT 的值设得太大或者 tail_space 的计算有误。</p><h3 id="step-4-处理堆空间不足的情况" tabindex="-1">Step 4: 处理堆空间不足的情况 <a class="header-anchor" href="#step-4-处理堆空间不足的情况" aria-label="Permalink to &quot;Step 4: 处理堆空间不足的情况&quot;">​</a></h3><p><strong>目标</strong>: 当空闲链表中找不到合适的块时，调用 expand 扩展堆区域，然后重试分配。</p><p><strong>设计思路</strong>: 搜索循环正常结束后如果还没有找到合适的块（curr 变成了 nullptr），说明当前堆空间不够用了。此时调用 <code>expand(size + align + HEADER_SIZE)</code> 向 VMM 申请新的虚拟地址空间。expand 函数会在堆的末尾映射新的物理页并创建新的空闲块（下一章详细讲解）。扩展完成后，递归调用 <code>alloc(size, align)</code> 重试分配。这个递归是安全的——expand 保证至少添加 size + align + HEADER_SIZE 字节的新空间，所以重试时一定能找到足够大的空闲块，不会无限递归。</p><p><strong>踩坑预警</strong>: 理论上，如果 PMM 在 expand 过程中耗尽物理内存，expand 会提前返回（不完整扩展），然后重试时可能再次搜索失败，再次调用 expand，如此循环直到栈溢出。在实践中，内核堆的扩展需求不会太大（几百 KB 到几 MB），128 MB 的 QEMU 内存绰绰有余。但如果你在做压力测试时内核突然 triple fault，可能是这个递归在极端情况下把栈撑爆了。</p><p>一个更安全的做法是把递归改为循环——在 alloc 末尾用 <code>goto retry</code> 或者把整个搜索逻辑包在 <code>while(true)</code> 循环里。但递归在这里最多只有一层（expand 保证映射足够空间），所以实际上不是问题。只有当 expand 因为 OOM 失败时才会出现无限递归，而 OOM 本身就是系统无法继续工作的信号。</p><p><strong>验证</strong>: 分配超过 64 KB 的内存（比如分配一个 80 KB 的块），应该能触发 expand。串口输出中会看到 <code>[HEAP] Expanded by XX KB, total XX KB</code> 的消息，然后分配成功返回。</p><h2 id="本章小结" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><p>本章实现了 alloc 的完整逻辑——first-fit 搜索、对齐计算、front padding、块分裂、以及空间不足时的自动扩展。alloc 是堆分配器中最复杂的函数，它需要在一次链表遍历中同时处理搜索、对齐和分裂三个需求。理解了 alloc 之后，下一章的 free、coalesce 和 expand 就相对简单了。</p><h2 id="构建与运行" tabindex="-1">构建与运行 <a class="header-anchor" href="#构建与运行" aria-label="Permalink to &quot;构建与运行&quot;">​</a></h2><p>本章完成了 <code>Heap::alloc()</code> 的实现，在 <code>heap.cpp</code> 中新增了约 100 行代码（包含辅助函数和搜索逻辑）。构建后运行 QEMU 测试：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cmake</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./build/run_qemu.sh</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果你在 main.cpp 中临时添加几个 alloc 调用和 dump_stats，串口输出应该类似：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[HEAP] Initialised at 0xFFFF800000000000, size 64 KB</span></span>
<span class="line"><span>[HEAP] Stats: total=64 KB, used=0 KB, free_list=63 KB, blocks=1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>分配几个块后再调用 dump_stats：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[HEAP] Stats: total=64 KB, used=1 KB, free_list=62 KB, blocks=1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>注意 <code>used</code> 和 <code>free_list</code> 的和不等于 <code>total</code>——差值是 header 开销和内部碎片。每次分配的 used 增量是 <code>HEADER_SIZE + size</code>（不只是 size），所以分配一个 64 字节的块实际上消耗了 96 字节（32 header + 64 payload）。</p><h2 id="调试技巧" tabindex="-1">调试技巧 <a class="header-anchor" href="#调试技巧" aria-label="Permalink to &quot;调试技巧&quot;">​</a></h2><p><strong>alloc 返回的指针不对齐</strong>: 在 alloc 的搜索循环里，<code>aligned_payload</code> 的计算依赖于 <code>align_up</code>。如果你发现返回的地址 <code>% 16 != 0</code>，检查 align_up 的实现——最常见的问题是 <code>~(align - 1)</code> 写成了 <code>~align - 1</code>。你也可以用 kprintf 打印 <code>aligned_payload</code> 的值和 <code>aligned_payload % align</code>，确认对齐计算正确。</p><p><strong>分配后写入数据但读回不一致</strong>: 如果写入 payload 的数据和读回的不同，可能是 VMM 的映射有问题——两个不同的虚拟地址映射到了同一个物理页，或者某个虚拟地址没有被映射。在 QEMU 中可以使用 <code>info tlb</code> 命令检查 TLB 内容，确认堆区域的虚拟地址确实映射到了正确的物理页。</p><p><strong>分配后 free_list 为空</strong>: 如果分配了一个小块（比如 64 字节）后 dump_stats 显示 blocks=0，说明 tail splitting 没有执行。检查 tail_space 的计算——可能是 block_end 算错了，或者 MIN_SPLIT 的值设得太大。正确的 tail_space 应该是 <code>block_end - (aligned_payload + size)</code>，也就是分配块之后到空闲块末尾的剩余字节数。</p><p><strong>front padding 导致 free 失败</strong>: 如果在测试大对齐（4096）时 free 报 &quot;magic mismatch&quot;，检查分配块的头部是否写在了 <code>aligned_payload - HEADER_SIZE</code> 而不是空闲块的起始地址。正确的 header_from_ptr 逻辑是 <code>ptr - HEADER_SIZE</code>——如果 free 时 payload 指针减去 32 后找不到正确的 magic，说明分配时头部位置写错了。</p><p><strong>多次分配后地址重叠</strong>: 如果两个 alloc 调用返回了重叠的地址范围，说明 tail splitting 创建的新空闲块的位置或大小不对。新块的 BlockHeader 应该位于 <code>aligned_payload + size</code>，它的 size 应该是 <code>tail_space - HEADER_SIZE</code>。如果新块的位置算错了（比如忘了加 HEADER_SIZE），它的 payload 区域就会和上一个分配块重叠。</p><p><strong>used_ 的值不准确</strong>: 如果分配后 used_ 的增长量不是 <code>HEADER_SIZE + size</code>，说明计算公式写错了。常见的错误是只加了 <code>size</code> 没加 <code>HEADER_SIZE</code>，或者把 <code>size</code> 算成了 <code>needed</code>（包含了 alignment padding）。正确的做法是 <code>used_ += HEADER_SIZE + size</code>，其中 <code>size</code> 是用户请求的原始大小，不包含对齐 padding。</p><h2 id="本章小结-1" tabindex="-1">本章小结 <a class="header-anchor" href="#本章小结-1" aria-label="Permalink to &quot;本章小结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>要点</th></tr></thead><tbody><tr><td>First-fit</td><td>线性扫描空闲链表，找到第一个足够大的块</td></tr><tr><td>对齐计算</td><td>aligned_payload = align_up(block_start + HEADER_SIZE, align)</td></tr><tr><td>Front padding</td><td>头部位于 aligned_payload - HEADER_SIZE，间隙可能成为小空闲块</td></tr><tr><td>Tail splitting</td><td>剩余空间 &gt;= MIN_SPLIT (48) 时创建新空闲块</td></tr><tr><td>MIN_SPLIT</td><td>HEADER_SIZE(32) + 16 = 48 字节，确保新空闲块有存在价值</td></tr><tr><td>alloc(0)</td><td>返回 nullptr，拒绝零大小请求</td></tr><tr><td>搜索失败</td><td>调用 expand 扩展堆区域，递归重试分配</td></tr><tr><td>needed 计算</td><td>size + (align - 1)，按最坏对齐开销预估所需空间</td></tr></tbody></table><h2 id="扩展方向" tabindex="-1">扩展方向 <a class="header-anchor" href="#扩展方向" aria-label="Permalink to &quot;扩展方向&quot;">​</a></h2><p>如果你想进一步改进 alloc 的性能，有几个方向可以考虑：</p><p><strong>分离空闲链表</strong>：将空闲块按大小范围分到不同的链表中（如 SLOB 的三链表设计）。小请求（&lt; 256 字节）只搜索小链表，减少搜索时间。这在空闲块数量很多时效果明显，但对于几十个块的内核堆来说改善有限。</p><p><strong>Best-fit 搜索</strong>：遍历整个链表找到最小的够用块。理论上碎片更少，但每次分配都是 O(n)。可以通过维护按大小排序的链表来折中——插入时按大小排序（O(n)），但搜索时可以提前终止。</p><p><strong>Buddy 系统替代</strong>：用 buddy 分配器替代 free list，合并操作变为 O(1)。但 buddy 系统只能分配 2 的幂次大小的块，内部碎片更大。适合作为物理页管理（Linux 的做法），不太适合内核堆的任意大小分配。</p><p><strong>缓存最近释放的块</strong>：维护一个小的&quot;最近释放&quot;缓存（比如最近释放的 4 个块），alloc 时先在缓存中查找。刚释放的块很可能还在 CPU 缓存中，命中率更高。这是 glibc malloc 的 ptmalloc 使用的策略之一。</p><p>alloc 是堆分配器中最复杂的函数。理解了 first-fit 搜索、对齐计算、front padding 和 tail splitting 之后，后面的 free、coalesce 和 expand 相对来说就更容易理解了。下一章我们将实现这三个函数，完成堆分配器的核心功能。</p><p>到目前为止，本章的代码约 100 行，覆盖了 alloc 的完整实现路径。每个分支（零大小、搜索命中、搜索失败）都有对应的处理逻辑。在正常的使用场景下，alloc 的大部分时间花在搜索循环中——遍历空闲链表找到第一个够大的块。</p><p>构建命令和运行方式和上一章完全相同。本章新增的代码全在 <code>kernel/mm/heap.cpp</code> 中，不需要修改 <code>CMakeLists.txt</code>。</p><p>如果你在测试中遇到 alloc 返回 nullptr 但堆明明有空间的情况，请参考上面的&quot;调试技巧&quot;部分逐一排查。</p>`,93)])])}const h=a(l,[["render",r]]);export{g as __pageData,h as default};
